function Navbar({ current, navigate }) {
  const [open, setOpen] = useState(false);
  const links = [
    { label: "Contact", page: "contact" },
    { label: "About", page: "about" },
    { label: "Donate", page: "donate" },
    { label: "Programmes", page: "programmes" },
    { label: "NeuroFlex", page: "neuroflex" },
  ];

  return (
    <header className="fixed top-0 left-0 right-0 z-50 bg-white/95 backdrop-blur-sm border-b border-black/[0.07]">
      <div className="max-w-7xl mx-auto px-6 h-14 flex items-center justify-between">
        <button onClick={() => navigate("home")} className="flex items-center gap-2.5 hover:opacity-60 transition-opacity">
          <img src={LOGO} alt="Brain Health Trust" className="h-7 w-7 object-contain" />
          <span className="font-display font-semibold tracking-tight text-black" style={{ fontSize: "13px" }}>Brain Health Trust South Africa</span>
        </button>

        <nav className="hidden md:flex items-center gap-10">
          {links.map(({ label, page }) => (
            <button key={page} onClick={() => navigate(page)}
              className={`transition-colors relative group ${current === page ? "text-black font-medium" : "text-black/40 hover:text-black"}`}
              style={{ fontSize: "13px" }}>
              {label}
              <span className={`absolute -bottom-0.5 left-0 h-px bg-black transition-all duration-300 ${current === page ? "w-full" : "w-0 group-hover:w-full"}`} />
            </button>
          ))}
        </nav>

        <button onClick={() => setOpen(!open)} className="md:hidden p-1 text-black/50" aria-label="Toggle menu">
          {open ? <X size={18} /> : <Menu size={18} />}
        </button>
      </div>

      {open && (
        <div className="md:hidden border-t border-black/[0.07]" style={{ backgroundColor: "#F0EEE9" }}>
          {links.map(({ label, page }) => (
            <button key={page} onClick={() => { navigate(page); setOpen(false); }}
              className="w-full text-left px-6 py-4 text-black/50 hover:text-black border-b border-black/[0.05] last:border-0 transition-colors" style={{ fontSize: "13px" }}>
              {label}
            </button>
          ))}
        </div>
      )}
    </header>
  );
}

