function ContactPage() {
  const [form, setForm] = useState({ name: "", email: "", message: "" });
  const [status, setStatus] = useState("idle"); // idle | sending | sent | error
  const sent = status === "sent";

  // Form delivery via FormSubmit.co — no account or key needed.
  // One-time activation: the first submission triggers a confirmation email
  // to eddie@neuroflex.io; once that link is clicked, all messages arrive by email.
  async function handleSubmit(e) {
    e.preventDefault();
    setStatus("sending");
    try {
      const res = await fetch("https://formsubmit.co/ajax/eddie@neuroflex.io", {
        method: "POST",
        headers: { "Content-Type": "application/json", Accept: "application/json" },
        body: JSON.stringify({
          _subject: `Website enquiry from ${form.name || "the Brain Health Trust website"}`,
          name: form.name,
          email: form.email,
          message: form.message,
        }),
      });
      const data = await res.json();
      if (data.success === "true" || data.success === true) {
        setStatus("sent");
      } else {
        setStatus("error");
      }
    } catch {
      setStatus("error");
    }
  }

  return (
    <>
      <PageHeader eyebrow="Get in touch with our team" title="Contact Us" />

      <section className="py-24 px-6">
        <div className="max-w-7xl mx-auto grid md:grid-cols-[5fr_7fr] gap-20 md:gap-32 items-start">
          <div>
            {sent ? (
              <div className="py-12">
                <div className="w-12 h-12 flex items-center justify-center mb-8 border border-black/10">
                  <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" className="text-black/50">
                    <polyline points="20 6 9 17 4 12" />
                  </svg>
                </div>
                <h2 className="font-display font-semibold text-2xl text-black mb-3">Message sent</h2>
                <p className="text-black/40" style={{ fontSize: "15px" }}>Thank you for reaching out. We'll get back to you soon.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="flex flex-col gap-10">
                {[
                  { id: "name", label: "Name", type: "text", placeholder: "Your name", required: false },
                  { id: "email", label: "Email", type: "email", placeholder: "your@email.com", required: true },
                ].map(({ id, label, type, placeholder, required }) => (
                  <div key={id} className="flex flex-col gap-3">
                    <label htmlFor={id} className="uppercase text-black/30 font-medium" style={{ fontSize: "11px", letterSpacing: "0.18em" }}>
                      {label}{required && <span className="text-black/20 ml-2 normal-case tracking-normal">(required)</span>}
                    </label>
                    <input id={id} type={type} required={required} placeholder={placeholder}
                      value={form[id]}
                      onChange={(e) => setForm({ ...form, [id]: e.target.value })}
                      className="w-full bg-transparent border-b border-black/12 py-3 text-black placeholder:text-black/18 focus:outline-none focus:border-black/40 transition-colors" style={{ fontSize: "15px" }} />
                  </div>
                ))}

                <div className="flex flex-col gap-3">
                  <label htmlFor="message" className="uppercase text-black/30 font-medium" style={{ fontSize: "11px", letterSpacing: "0.18em" }}>Message</label>
                  <textarea id="message" rows={5} placeholder="Your message…" value={form.message}
                    onChange={(e) => setForm({ ...form, message: e.target.value })}
                    className="w-full bg-transparent border-b border-black/12 py-3 text-black placeholder:text-black/18 focus:outline-none focus:border-black/40 transition-colors resize-none" style={{ fontSize: "15px" }} />
                </div>

                <div className="pt-2">
                  <button type="submit" disabled={status === "sending"}
                    className="inline-flex items-center gap-2 font-medium text-white px-8 py-3 rounded-full hover:bg-black transition-colors group disabled:opacity-60"
                    style={{ fontSize: "13px", backgroundColor: "#2F1563" }}>
                    {status === "sending" ? "Sending…" : "Send"}
                    <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform" />
                  </button>
                  {status === "error" && (
                    <p className="text-black/50 mt-4" style={{ fontSize: "13px" }}>
                      Sorry, your message couldn't be sent right now. Please email us directly at{" "}
                      <a href="mailto:eddie@neuroflex.io" className="text-black underline">eddie@neuroflex.io</a>.
                    </p>
                  )}
                </div>
              </form>
            )}
          </div>

          <img src={CONTACT_PHOTO} alt="Community rugby match on a sports field in front of Cape Town Stadium" className="w-full object-cover" style={{ height: "540px" }} />
        </div>
      </section>
    </>
  );
}

// ---------------------------------------------------------------------------
// Root
// ---------------------------------------------------------------------------

export default function App() {
  const [page, setPage] = useState("home");

  useEffect(() => {
    // Set the browser tab title
    document.title = "Brain Health Trust South Africa";
    // Set the favicon (tab icon) to the BHT logo
    let link = document.querySelector("link[rel~='icon']");
    if (!link) {
      link = document.createElement("link");
      link.rel = "icon";
      document.head.appendChild(link);
    }
    link.type = "image/png";
    link.href = LOGO;
  }, []);

  function navigate(p) {
    setPage(p);
    window.scrollTo({ top: 0, behavior: "instant" });
    document.documentElement.scrollTop = 0;
    document.body.scrollTop = 0;
  }

  const pages = {
    home: <HomePage navigate={navigate} />,
    about: <AboutPage navigate={navigate} />,
    programmes: <ProgrammesPage />,
    neuroflex: <NeuroFlexPage />,
    donate: <DonatePage />,
    contact: <ContactPage />,
  };

  return (
    <div className="bht-root min-h-screen text-black flex flex-col" style={{ backgroundColor: "#F0EEE9" }}>
      <GlobalStyle />
      <Navbar current={page} navigate={navigate} />
      <main className="flex-1 pt-14">{pages[page]}</main>
      <Footer navigate={navigate} />
    </div>
  );
}
